5	<div class="space-y-6">
6	
7	  <!-- Header -->
8	  <div class="flex items-start justify-between">
9	    <div>
10	      <div class="flex items-center gap-3">
11	        <h1 class="text-lg font-semibold text-neutral-900">{{ deal.deal_id }}</h1>
12	        <span class="rounded bg-neutral-100 px-2 py-0.5 text-xs font-medium text-neutral-600">
13	          {{ deal.stage | replace('_', ' ') | title }}
14	        </span>
15	      </div>
16	      {% if issuer %}
17	      <p class="mt-0.5 text-sm text-neutral-500">{{ issuer.name }} · {{ deal.shares | int | format_number }} shares @ ${{ "%.2f"|format(deal.price_per_share) }}</p>
18	      {% endif %}
19	    </div>
20	    <div class="flex items-center gap-3">
21	      <a href="/brief" class="text-sm text-neutral-400 hover:text-neutral-600">← Brief</a>
22	      {% if debug %}
23	      <a href="/debug/deal/{{ deal.deal_id }}" class="text-xs text-purple-500 hover:text-purple-700 font-mono">⟩ debug view</a>
24	      {% else %}
25	      <a href="?debug=1" class="text-xs text-neutral-300 hover:text-neutral-500">debug</a>
26	      {% endif %}
27	    </div>
28	  </div>
29	
30	  <!-- Deal facts -->
31	  <div class="grid grid-cols-2 gap-3 sm:grid-cols-4">
32	    {% macro fact(label, value) %}
33	    <div class="rounded border border-neutral-100 bg-white px-4 py-3">
34	      <p class="text-xs text-neutral-400 uppercase tracking-wide">{{ label }}</p>
35	      <p class="mt-1 text-sm font-medium text-neutral-800">{{ value or '—' }}</p>
36	    </div>
37	    {% endmacro %}
38	    {{ fact("Stage entered", deal.stage_entered_at[:10] if deal.stage_entered_at else '—') }}
39	    {{ fact("Responsible", deal.responsible_party | replace('_', ' ') if deal.responsible_party else '—') }}
40	    {{ fact("ROFR deadline", deal.rofr_deadline[:10] if deal.rofr_deadline else 'None') }}
41	    {{ fact("Buyer", deal.buyer_id) }}
42	  </div>
43	
44	  <!-- Event timeline -->
45	  <div>
46	    <h2 class="text-sm font-semibold text-neutral-700 mb-3">Event Timeline</h2>
47	    {% if events %}
48	    <div class="space-y-1">
49	      {% for ev in events | sort(attribute='occurred_at', reverse=True) %}
50	      <div class="flex items-start gap-3 text-xs">
51	        <span class="flex-shrink-0 text-neutral-400 font-mono">{{ ev.occurred_at[:10] }}</span>
52	        <span class="rounded px-1.5 py-0.5
53	          {% if ev.event_type == 'comm_outbound' %}bg-blue-50 text-blue-700
54	          {% elif ev.event_type == 'comm_inbound' %}bg-green-50 text-green-700
55	          {% elif ev.event_type == 'stage_transition' %}bg-neutral-100 text-neutral-600
56	          {% elif ev.event_type == 'comm_sent_agent_recommended' %}bg-purple-50 text-purple-700
57	          {% else %}bg-neutral-50 text-neutral-500{% endif %}
58	        ">{{ ev.event_type | replace('_', ' ') }}</span>
59	        <span class="text-neutral-600">{{ ev.summary }}</span>
60	      </div>
61	      {% endfor %}
62	    </div>
63	    {% else %}
64	    <p class="text-xs text-neutral-400">No events yet.</p>
65	    {% endif %}
66	  </div>
67	
68	  <!-- Agent observations -->
69	  <div>
70	    <h2 class="text-sm font-semibold text-neutral-700 mb-3">Agent Observations ({{ observations | length }})</h2>
71	    {% if observations %}
72	    <div class="space-y-3">
73	      {% for obs in observations | sort(attribute='observed_at', reverse=True) %}
74	      <div class="rounded border border-neutral-100 bg-white px-4 py-3 text-xs" x-data="{ show: false }">
75	        <div class="flex items-center justify-between">
76	          <div class="flex items-center gap-2">
77	            <span class="font-mono text-neutral-400">{{ obs.observed_at[:16] }}</span>
78	            {% if obs.severity == 'escalate' %}
79	              <span class="rounded-full bg-red-100 px-2 py-0.5 font-semibold text-red-700">ESCALATE</span>
80	            {% elif obs.severity == 'act' %}
81	              <span class="rounded-full bg-amber-100 px-2 py-0.5 font-semibold text-amber-700">ACT</span>
82	            {% elif obs.severity == 'watch' %}
83	              <span class="rounded-full bg-blue-100 px-2 py-0.5 font-semibold text-blue-600">WATCH</span>
84	            {% else %}
85	              <span class="rounded-full bg-neutral-100 px-2 py-0.5 text-neutral-500">INFO</span>
86	            {% endif %}
87	            {% for dim in obs.reasoning_parsed.get('dimensions_triggered', []) %}
88	            <span class="bg-neutral-100 px-1.5 py-0.5 rounded text-neutral-500">{{ dim | replace('_', ' ') }}</span>
89	            {% endfor %}
90	          </div>
91	          <button x-on:click="show = !show" class="text-neutral-400 hover:text-neutral-600"
92	            x-text="show ? 'Hide reasoning' : 'Show reasoning'"></button>
93	        </div>
94	
95	        <div x-show="show" x-cloak class="mt-3 space-y-2">
96	          {% if obs.reasoning_parsed.get('error') %}
97	          <div class="rounded bg-red-50 border border-red-100 px-3 py-2 text-xs text-red-600">
98	            LLM error: {{ obs.reasoning_parsed.get('error') }}
99	          </div>
100	          {% else %}

